import React,{useState,useEffect}from"react";
const DV_PURPLE="#6D28D9",DV_GRAD1="#7C3AED",DV_GRAD2="#4F46E5";
const BG="#F5F3FF",WH="#fff",BR="#E2E8F0",DK="#1E293B",BL="#1565C0";
const HDR_BG="linear-gradient(135deg,#1E1B4B,#312E81,#1565C0)";
const MHE=["","ינואר","פברואר","מרץ","אפריל","מאי","יוני","יולי","אוגוסט","ספטמבר","אוקטובר","נובמבר","דצמבר"];
const MONTHS_CTX={1:'ינואר - חודש חורפי, אחרי החגים',2:'פברואר - חודש קצר, לפני פורים',3:'מרץ - אביב מתחיל, פורים, ראש חודש ניסן',4:'אפריל - פסח, חג החירות',5:'מאי - חודש אביבי, יום העצמאות',6:'יוני - קיץ מתחיל',7:'יולי - שיא הקיץ',8:'אוגוסט - חופשות קיץ',9:'ספטמבר - חזרה לשגרה, ראש השנה',10:'אוקטובר - סוכות, חגי תשרי',11:'נובמבר - חורף מתחיל',12:'דצמבר - חנוכה, סוף שנה'};
const YEARS=[2025,2026,2027];

const TEN_LOGO="data:image/png;base64,";
const DV_LOGO="data:image/png;base64,";

const SmartLogo=({src,alt,style})=>{
  const[err,setErr]=useState(false);
  if(err||!src)return<div style={{...style,display:"flex",alignItems:"center",justifyContent:"center",background:DV_PURPLE,color:WH,fontWeight:"bold",fontSize:(style.width||40)/3,borderRadius:"8px"}}>{alt}</div>;
  return<img src={src} alt={alt} style={style} onError={()=>setErr(true)}/>;
};

async function callAI(prompt){
  try{
    const r=await fetch("/api/ai",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({prompt})});
    if(!r.ok)throw new Error();
    const d=await r.json();
    return(d.text||"").trim();
  }catch(e){return"שגיאה בייצור הטקסט.";}
}

function Badge({type}){
  const m={"שני חסכוני":["#DBEAFE",BL],"חג / אירוע":["#DCFCE7","#166534"],"מצחיק / אפליקציה":["#FEF3C7","#92400E"],"דרושים":["#FCE7F3","#9D174D"],"פוסט מבצע":["#FFE4E6","#9F1239"]};
  const[bg,color]=m[type]||["#F3F4F6","#374151"];
  return<span style={{padding:"3px 10px",borderRadius:20,fontSize:11,fontWeight:800,background:bg,color,whiteSpace:"nowrap"}}>{type}</span>;
}

function StatusIcon({status}){
  if(status==="done")return<span title="מוכן" style={{fontSize:18}}>✅</span>;
  return<span title="ממתין" style={{fontSize:18,opacity:0.4}}>⏳</span>;
}

function PostRow({post,onOpen}){
  return(
    <tr onClick={()=>onOpen(post)} style={{cursor:"pointer",borderBottom:`1px solid ${BR}`}}>
      <td style={{padding:"10px 14px",fontWeight:700,color:DK,textAlign:"right"}}>{post.id}</td>
      <td style={{padding:"10px 14px",textAlign:"right"}}>{post.date||"לפי מבצע"}</td>
      <td style={{padding:"10px 14px",textAlign:"right"}}>{post.day||""}</td>
      <td style={{padding:"10px 14px",textAlign:"right"}}><Badge type={post.type}/></td>
      <td style={{padding:"10px 14px",textAlign:"center"}}><StatusIcon status={post.copy?"done":"pending"}/></td>
    </tr>
  );
}

function PostModal({post,onClose,onUpdate,context}){
  const[loading,setLoading]=useState(false);
  const[copy,setCopy]=useState(post.copy||"");
  useEffect(()=>{if(!post.copy&&!loading)autoGenerate();},[]);
  async function autoGenerate(){
    setLoading(true);
    const txt=await callAI(`כתוב פוסט מקצועי קצר ומושך לדף הפייסבוק של דלק Ten עבור: ${post.type}. הקשר חודשי: ${context}. הפוסט צריך להיות חם, ישראלי, ולעורר מעורבות. עד 5 שורות.`);
    setCopy(txt);
    onUpdate({...post,copy:txt});
    setLoading(false);
  }
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,direction:"rtl"}}>
      <div style={{background:WH,borderRadius:24,padding:35,width:"90%",maxWidth:580,boxShadow:"0 25px 60px rgba(0,0,0,0.3)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <span style={{background:"#F1F5F9",color:DV_PURPLE,width:32,height:32,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:14}}>#{post.id}</span>
            <span style={{fontWeight:800,fontSize:18,color:DK}}>{post.date||"לפי מבצע"}</span>
            <Badge type={post.type}/>
          </div>
          <button onClick={onClose} style={{background:"#F1F5F9",border:"none",width:32,height:32,borderRadius:"50%",cursor:"pointer",fontSize:16}}>✕</button>
        </div>
        <div style={{background:"#F8FAFC",borderRadius:16,border:`1px solid ${BR}`,minHeight:140,padding:20,marginBottom:20,color:"#334155",lineHeight:1.8,fontSize:15,whiteSpace:"pre-wrap"}}>
          {loading?"🪄 מייצר תוכן אוטומטית...":copy||"לחץ על ייצר כדי ליצור תוכן"}
        </div>
        <div style={{display:"flex",gap:10}}>
          <button onClick={autoGenerate} style={{flex:1,padding:"12px",background:DV_PURPLE,color:WH,border:"none",borderRadius:12,fontWeight:700,cursor:"pointer"}}>🪄 ייצר מחדש</button>
          <button onClick={()=>{navigator.clipboard.writeText(copy);}} style={{padding:"12px 18px",background:"#F1F5F9",border:"none",borderRadius:12,fontWeight:700,cursor:"pointer"}}>📋 העתק</button>
        </div>
      </div>
    </div>
  );
}

export default function App(){
  const[view,setView]=useState("select-client");
  const[client,setClient]=useState(null);
  const[month,setMonth]=useState(new Date().getMonth()+1);
  const[year,setYear]=useState(new Date().getFullYear());
  const[extraCtx,setExtraCtx]=useState("");
  const[posts,setPosts]=useState([]);
  const[openPost,setOpenPost]=useState(null);
  const[savedGantts,setSavedGantts]=useState([]);
  const[generating,setGenerating]=useState(false);
  const[genProgress,setGenProgress]=useState(0);

  const context=MONTHS_CTX[month]+(extraCtx?" | "+extraCtx:"");

  const DAYS=["","א","ב","ג","ד","ה","ו","ש"];
  function getDay(d,m,y){const day=new Date(y,m-1,d).getDay();return["ראשון","שני","שלישי","רביעי","חמישי","שישי","שבת"][day];}

  function buildTemplate(){
    return[
      {id:1,type:"שני חסכוני",date:`2.${month}.${year}`,day:getDay(2,month,year)},
      {id:2,type:"חג / אירוע",date:`4.${month}.${year}`,day:getDay(4,month,year)},
      {id:3,type:"מצחיק / אפליקציה",date:`9.${month}.${year}`,day:getDay(9,month,year)},
      {id:4,type:"דרושים",date:`16.${month}.${year}`,day:getDay(16,month,year)},
      {id:5,type:"שני חסכוני",date:`30.${month}.${year}`,day:getDay(30,month,year)},
      {id:6,type:"פוסט מבצע",date:null,day:null},
      {id:7,type:"פוסט מבצע",date:null,day:null},
      {id:8,type:"פוסט מבצע",date:null,day:null},
      {id:9,type:"פוסט מבצע",date:null,day:null},
    ];
  }

  async function buildGantt(){
    const template=buildTemplate();
    setPosts(template);
    setView("gantt");
    setGenerating(true);
    setGenProgress(0);
    const updated=[...template];
    for(let i=0;i<5;i++){
      const copy=await callAI(`כתוב פוסט מקצועי קצר ומושך לדף הפייסבוק של דלק Ten עבור: ${updated[i].type}. הקשר חודשי: ${context}. עד 5 שורות.`);
      updated[i]={...updated[i],copy};
      setPosts([...updated]);
      setGenProgress(i+1);
    }
    setGenerating(false);
    const ganttKey={month,year,date:new Date().toLocaleDateString("he-IL")};
    setSavedGantts(prev=>[ganttKey,...prev.slice(0,4)]);
  }

  const doneCount=posts.filter(p=>p.copy).length;

  if(view==="select-client")return(
    <div style={{minHeight:"100vh",background:BG,display:"flex",alignItems:"center",justifyContent:"center",direction:"rtl",fontFamily:"system-ui"}}>
      <div style={{background:WH,padding:45,borderRadius:35,boxShadow:"0 25px 60px -12px rgba(0,0,0,0.12)",textAlign:"center",width:"95%",maxWidth:460}}>
        <SmartLogo src={DV_LOGO} alt="David Vatine" style={{width:120,height:63,objectFit:"contain",borderRadius:8,margin:"0 auto 30px",display:"block"}}/>
        <h2 style={{color:DV_PURPLE,fontWeight:800,fontSize:30,marginBottom:10}}>בחר לקוח</h2>
        <p style={{color:"#64748B",marginBottom:35}}>בחר לקוח ליצירת גאנט</p>
        <div onClick={()=>{setClient("Ten");setView("setup");}}
          style={{border:`2px solid ${DV_PURPLE}`,borderRadius:22,padding:"22px 26px",display:"flex",alignItems:"center",justifyContent:"space-between",cursor:"pointer",background:WH,marginBottom:16,transition:"box-shadow .2s"}}
          onMouseEnter={e=>e.currentTarget.style.boxShadow="0 8px 25px rgba(109,40,217,0.2)"}
          onMouseLeave={e=>e.currentTarget.style.boxShadow="none"}>
          <span style={{color:DV_PURPLE,fontSize:20}}>←</span>
          <div style={{display:"flex",alignItems:"center",gap:15}}>
            <span style={{fontWeight:700,fontSize:22,color:DK}}>דלק Ten</span>
            <SmartLogo src={TEN_LOGO} alt="Ten" style={{width:45,height:45,borderRadius:"50%",objectFit:"cover"}}/>
          </div>
        </div>
        <button onClick={()=>alert("בקרוב...")} style={{width:"100%",padding:"18px 26px",border:"2px dashed #CBD5E1",borderRadius:22,background:"transparent",cursor:"pointer",color:"#94A3B8",fontSize:16,fontWeight:600}}>
          ➕ הוסף לקוח חדש
        </button>
      </div>
    </div>
  );

  if(view==="setup")return(
    <div style={{minHeight:"100vh",background:BG,display:"flex",alignItems:"center",justifyContent:"center",direction:"rtl",fontFamily:"system-ui"}}>
      <div style={{background:WH,padding:40,borderRadius:28,boxShadow:"0 25px 60px -12px rgba(0,0,0,0.12)",width:"95%",maxWidth:520}}>
        <h2 style={{color:DK,fontWeight:800,fontSize:26,marginBottom:24,textAlign:"center"}}>בחר חודש לגאנט</h2>
        <div style={{display:"flex",gap:12,marginBottom:20}}>
          <select value={month} onChange={e=>setMonth(+e.target.value)} style={{flex:2,padding:"14px 16px",borderRadius:14,border:`2px solid ${BR}`,fontSize:16,fontWeight:700,background:WH}}>
            {MHE.map((m,i)=>i>0&&<option key={i} value={i}>{m}</option>)}
          </select>
          <select value={year} onChange={e=>setYear(+e.target.value)} style={{flex:1,padding:"14px 16px",borderRadius:14,border:`2px solid ${BR}`,fontSize:16,fontWeight:700,background:WH}}>
            {YEARS.map(y=><option key={y} value={y}>{y}</option>)}
          </select>
        </div>
        <div style={{background:"#F0FDF4",border:"1px solid #BBF7D0",borderRadius:14,padding:"14px 18px",marginBottom:20,fontSize:14,color:"#166534"}}>
          🗓️ <strong>הקשר ל-{MHE[month]} {year}:</strong><br/>{MONTHS_CTX[month]}
        </div>
        <textarea value={extraCtx} onChange={e=>setExtraCtx(e.target.value)} placeholder="📝 הקשר תקשורתי נוסף (אופציונלי)&#10;למשל: עליה במחירי דלק, גל חום..." style={{width:"100%",padding:"14px 16px",borderRadius:14,border:`2px solid ${BR}`,fontSize:14,minHeight:80,resize:"vertical",fontFamily:"system-ui",boxSizing:"border-box",marginBottom:20}}/>
        <div style={{background:"#FFF7ED",border:"1px solid #FED7AA",borderRadius:14,padding:"14px 18px",marginBottom:24,fontSize:13,color:"#92400E"}}>
          🚀 <strong>מה יקרה:</strong><br/>
          ✅ 5 פוסטים ייווצרו אוטומטית ← ○ 4 פוסטי מבצע ריקים<br/>
          💾 שמירה אוטומטית ← עריכה הדף לא ימחק כלום<br/>
          ✨ ייצוא: העתק טקסט / תצוגה מקדימה ללקוח
        </div>
        <button onClick={buildGantt} style={{width:"100%",padding:"18px",background:"#1E3A5F",color:WH,border:"none",borderRadius:16,fontSize:18,fontWeight:900,cursor:"pointer"}}>
          🚀 בנה גאנט ל-{MHE[month]} {year}
        </button>
      </div>
    </div>
  );

  return(
    <div style={{minHeight:"100vh",background:"#F1F5F9",direction:"rtl",fontFamily:"system-ui"}}>
      <header style={{background:HDR_BG,padding:"14px 28px",display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,zIndex:100}}>
        <div style={{display:"flex",gap:10}}>
          {savedGantts.length>0&&<button onClick={()=>alert("גאנטים שמורים - בקרוב")} style={{background:"rgba(255,255,255,0.15)",color:WH,border:"none",padding:"8px 16px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:13}}>📁 גאנטים שמורים ({savedGantts.length})</button>}
          <button onClick={()=>alert("שיתוף ללקוח - בקרוב")} style={{background:"rgba(255,165,0,0.8)",color:WH,border:"none",padding:"8px 16px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:13}}>🔗 שתף ללקוח</button>
          <button onClick={()=>alert("ייצוא - בקרוב")} style={{background:"rgba(34,197,94,0.8)",color:WH,border:"none",padding:"8px 16px",borderRadius:10,cursor:"pointer",fontWeight:700,fontSize:13}}>📤 ייצוא</button>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <div style={{textAlign:"left"}}>
            <div style={{color:WH,fontWeight:800,fontSize:16}}>גאנט AI — דלק Ten</div>
            <div style={{color:"rgba(255,255,255,0.7)",fontSize:12}}>🌱 אביב | {doneCount}/{posts.length} מוכנים | שמירה אוטומטית</div>
          </div>
          <SmartLogo src={TEN_LOGO} alt="Ten" style={{width:40,height:40,borderRadius:"50%",objectFit:"cover"}}/>
        </div>
      </header>

      {generating&&(
        <div style={{background:"#EFF6FF",borderBottom:"1px solid #BFDBFE",padding:"12px 28px",display:"flex",alignItems:"center",gap:12}}>
          <span style={{fontSize:14,color:BL,fontWeight:600}}>🪄 מייצר {genProgress}/5 פוסטים אוטומטית...</span>
          <div style={{flex:1,background:"#DBEAFE",borderRadius:999,height:8}}>
            <div style={{width:`${(genProgress/5)*100}%`,background:BL,borderRadius:999,height:8,transition:"width .5s"}}/>
          </div>
        </div>
      )}

      <main style={{maxWidth:900,margin:"30px auto",padding:"0 20px"}}>
        <div style={{background:WH,borderRadius:20,boxShadow:"0 4px 20px rgba(0,0,0,0.06)",overflow:"hidden",marginBottom:24}}>
          <div style={{background:"#1E3A5F",color:WH,padding:"14px 20px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{fontWeight:800,fontSize:16}}>📋 סיכום גאנט | {MHE[month]} {year}</span>
            <span style={{fontSize:13,opacity:0.8}}>לחץ על כל שורה לפתיחת הפוסט המלא</span>
          </div>
          {extraCtx&&<div style={{background:"#FFFBEB",padding:"10px 20px",fontSize:13,color:"#92400E",borderBottom:`1px solid ${BR}`}}>📝 {extraCtx}</div>}
          <table style={{width:"100%",borderCollapse:"collapse"}}>
            <thead>
              <tr style={{background:"#F8FAFC"}}>
                {["#","תאריך","יום","סוג פוסט","סטטוס"].map(h=><th key={h} style={{padding:"10px 14px",textAlign:"right",fontSize:12,color:"#64748B",fontWeight:700,borderBottom:`1px solid ${BR}`}}>{h}</th>)}
              </tr>
            </thead>
            <tbody>
              {posts.map(p=><PostRow key={p.id} post={p} onOpen={setOpenPost}/>)}
            </tbody>
          </table>
        </div>

        {openPost&&posts.find(p=>p.id===openPost.id)?.copy&&(
          <div style={{background:WH,borderRadius:20,boxShadow:"0 4px 20px rgba(0,0,0,0.06)",padding:24,marginBottom:16}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <span style={{background:"#F1F5F9",color:DV_PURPLE,width:30,height:30,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:13}}>#{openPost.id}</span>
                <span style={{fontWeight:800,color:DK}}>{openPost.date||"לפי מבצע"} | {openPost.day||""}</span>
                <Badge type={openPost.type}/>
              </div>
              <span style={{color:"#10B981",fontWeight:700,fontSize:13}}>✅ מוכן</span>
            </div>
            <div style={{background:"#F8FAFC",borderRadius:14,padding:18,color:"#334155",lineHeight:1.8,fontSize:15,whiteSpace:"pre-wrap",marginBottom:16}}>
              {posts.find(p=>p.id===openPost.id)?.copy}
            </div>
            <div style={{display:"flex",gap:10}}>
              <button onClick={async()=>{
                const p=posts.find(x=>x.id===openPost.id);
                const copy=await callAI(`כתוב פוסט מקצועי קצר ומושך לדף הפייסבוק של דלק Ten עבור: ${p.type}. הקשר חודשי: ${context}. עד 5 שורות.`);
                setPosts(prev=>prev.map(x=>x.id===p.id?{...x,copy}:x));
                setOpenPost({...p,copy});
              }} style={{flex:1,padding:"10px",background:DV_PURPLE,color:WH,border:"none",borderRadius:10,fontWeight:700,cursor:"pointer"}}>🪄 ייצר מחדש</button>
              <button onClick={()=>navigator.clipboard.writeText(posts.find(p=>p.id===openPost.id)?.copy||"")} style={{padding:"10px 16px",background:"#F1F5F9",border:"none",borderRadius:10,fontWeight:700,cursor:"pointer"}}>📋</button>
            </div>
          </div>
        )}

        <button onClick={()=>setView("setup")} style={{background:"#F1F5F9",border:"none",padding:"10px 20px",borderRadius:12,fontWeight:700,cursor:"pointer",color:"#475569",marginBottom:30}}>
          ← חזרה להגדרות
        </button>
      </main>

      {openPost&&!posts.find(p=>p.id===openPost.id)?.copy&&(
        <PostModal post={openPost} context={context}
          onClose={()=>setOpenPost(null)}
          onUpdate={upd=>setPosts(prev=>prev.map(p=>p.id===upd.id?upd:p))}/>
      )}
    </div>
  );
}
